baseline.response_text:
{
  "models": [
    {
      "component_id": "comp-link-mapping-repository",
      "entities": [
        {
          "name": "LinkMapping",
          "fields": [
            {
              "name": "slug",
              "type": "string",
              "constraints": "unique, length 6, lowercase alphanumeric"
            },
            {
              "name": "original_url",
              "type": "string",
              "constraints": "encrypted_at_rest, aes-256"
            },
            {
              "name": "created_at",
              "type": "timestamp",
              "constraints": "utc_now"
            },
            {
              "name": "expires_at",
              "type": "timestamp",
              "constraints": "policy_expiry_event"
            },
            {
              "name": "is_active",
              "type": "boolean",
              "constraints": "default true"
            }
          ],
          "relationships": [
            {
              "to": null,
              "type": "one_to_one",
              "foreign_key": "slug"
            }
          ]
        },
        {
          "name": "PolicyExpiryEvent",
          "fields": [
            {
              "name": "link_id",
              "type": "uuid",
              "constraints": "references LinkMapping slug"
            },
            {
              "name": "expiry_timestamp",
              "type": "timestamp",
              "constraints": "not_null"
            }
          ],
          "relationships": [
            {
              "to": "LinkMapping",
              "type": "many_to_one",
              "foreign_key": "link_id",
              "direction": "child references parent"
            }
          ]
        }
      ]
    },
    {
      "component_id": "comp-delete-purger",
      "entities": [
        {
          "name": "DeletionRequest",
          "fields": [
            {
              "name": "request_id",
              "type": "uuid",
              "constraints": "primary_key"
            },
            {
              "name": "link_slug",
              "type": "string",
              "constraints": "references LinkMapping.slug, nullable if bulk"
            },
            {
              "name": "requested_at",
              "type": "timestamp",
              "constraints": "not_null"
            },
            {
              "name": "purged_at",
              "type": "timestamp",
              "constraints": "null if pending, max 24h gap to null"
            },
            {
              "name": "status",
              "type": "string",
              "constraints": "enum: pending, purged, failed"
            }
          ],
          "relationships": [
            {
              "to": "LinkMapping",
              "type": "many_to_one",
              "foreign_key": "link_slug",
              "direction": "child references parent"
            }
          ]
        }
      ]
    },
    {
      "component_id": "comp-gdpr-exporter",
      "entities": [
        {
          "name": "DataExportJob",
          "fields": [
            {
              "name": "job_id",
              "type": "uuid",
              "constraints": "primary_key"
            },
            {
              "name": "requested_user",
              "type": "string",
              "constraints": "nullable (system process)"
            },
            {
              "name": "start_at",
              "type": "timestamp",
              "constraints": "not_null"
            },
            {
              "name": "complete_at",
              "type": "timestamp",
              "constraints": "nullable"
            },
            {
              "name": "export_hash",
              "type": "string",
              "constraints": "sha256 of exported data"
            },
            {
              "name": "status",
              "type": "string",
              "constraints": "enum: queued, running, complete, failed"
            }
          ],
          "relationships": [
            {
              "to": null,
              "type": "one_to_one"
            }
          ]
        }
      ]
    },
    {
      "component_id": "comp-platform-audit",
      "entities": [
        {
          "name": "AuditLogRecord",
          "fields": [
            {
              "name": "log_id",
              "type": "uuid",
              "constraints": "primary_key"
            },
            {
              "name": "event_type",
              "type": "string",
              "constraints": "operation_type"
            },
            {
              "name": "payload",
              "type": "string",
              "constraints": "json_encoded"
            },
            {
              "name": "ingested_at",
              "type": "timestamp",
              "constraints": "not_null, retention >= 365 days"
            }
          ],
          "relationships": [
            {
              "to": null,
              "type": "one_to_one"
            }
          ]
        }
      ]
    },
    {
      "component_id": "comp-backup-replication-engine",
      "entities": [
        {
          "name": "BackupReplicationJob",
          "fields": [
            {
              "name": "job_id",
              "type": "uuid",
              "constraints": "primary_key"
            },
            {
              "name": "source_id",
              "type": "uuid",
              "constraints": "references data_store_primary"
            },
            {
              "name": "dest_id",
              "type": "uuid",
              "constraints": "references data_store_dr"
            },
            {
              "name": "checksum",
              "type": "string",
              "constraints": "sha256, zero integrity errors"
            },
            {
              "name": "status",
              "type": "string",
              "constraints": "enum: queued, in_progress, complete, failed"
            },
            {
              "name": "executed_at",
              "type": "timestamp",
              "constraints": "not_null if status complete"
            }
          ],
          "relationships": [
            {
              "to": null,
              "type": "one_to_one"
            }
          ]
        }
      ]
    },
    {
      "component_id": "comp-failure-detection",
      "entities": [
        {
          "name": "FailureEvent",
          "fields": [
            {
              "name": "event_id",
              "type": "uuid",
              "constraints": "primary_key"
            },
            {
              "name": "region_id",
              "type": "string",
              "constraints": "geo_location_identifier"
            },
            {
              "name": "detected_at",
              "type": "timestamp",
              "constraints": "not_null"
            },
            {
              "name": "severity",
              "type": "string",
              "constraints": "enum: warning, error, critical"
            }
          ],
          "relationships": [
            {
              "to": null,
              "type": "one_to_one"
            }
          ]
        }
      ]
    },
    {
      "component_id": "comp-recovery-planner",
      "entities": [
        {
          "name": "RecoveryPlan",
          "fields": [
            {
              "name": "plan_id",
              "type": "uuid",
              "constraints": "primary_key"
            },
            {
              "name": "trigger_event_id",
              "type": "uuid",
              "constraints": "references FailureEvent.event_id"
            },
            {
              "name": "rto_minutes",
              "type": "integer",
              "constraints": "<= 15 per SR-005"
            },
            {
              "name": "execution_sequence",
              "type": "array",
              "constraints": "json array of step_ids"
            },
            {
              "name": "completed_at",
              "type": "timestamp",
              "constraints": "nullable"
            }
          ],
          "relationships": [
            {
              "to": "FailureEvent",
              "type": "many_to_one",
              "foreign_key": "trigger_event_id",
              "direction": "child references parent"
            }
          ]
        }
      ]
    },
    {
      "component_id": "comp-request-timeout-enforcer",
      "entities": [
        {
          "name": "TimeoutConfig",
          "fields": [
            {
              "name": "config_id",
              "type": "uuid",
              "constraints": "primary_key"
            },
            {
              "name": "limit_ms",
              "type": "integer",
              "constraints": "max_duration_per_request"
            },
            {
              "name": "action_on_exceed",
              "type": "string",
              "constraints": "enum: kill, graceful_shutdown"
            }
          ],
          "relationships": [
            {
              "to": null,
              "type": "one_to_one"
            }
          ]
        }
      ]
    },
    {
      "component_id": "comp-rel-latency-monitor",
      "entities": [
        {
          "name": "LatencyMetric",
          "fields": [
            {
              "name": "metric_id",
              "type": "uuid",
              "constraints": "primary_key"
            },
            {
              "name": "endpoint",
              "type": "string",
              "constraints": "redirect_url"
            },
            {
              "name": "p95_value",
              "type": "integer",
              "constraints": "milliseconds, <= 100 per SR-003"
            },
            {
              "name": "window_start",
              "type": "timestamp",
              "constraints": "prometheus_rollup"
            },
            {
              "name": "status",
              "type": "string",
              "constraints": "enum: nominal, degraded"
            }
          ],
          "relationships": [
            {
              "to": null,
              "type": "one_to_one"
            }
          ]
        }
      ]
    },
    {
      "component_id": "comp-rel-uptime-verifier",
      "entities": [
        {
          "name": "UptimeMetric",
          "fields": [
            {
              "name": "metric_id",
              "type": "uuid",
              "constraints": "primary_key"
            },
            {
              "name": "uptime_percentage",
              "type": "decimal",
              "constraints": "float, >= 99.9 per SR-004"
            },
            {
              "name": "window_start",
              "type": "timestamp",
              "constraints": "rolling_30_days"
            },
            {
              "name": "verified",
              "type": "boolean",
              "constraints": "false until verification"
            }
          ],
          "relationships": [
            {
              "to": null,
              "type": "one_to_one"
            }
          ]
        }
      ]
    },
    {
      "component_id": "comp-sec-request-validation",
      "entities": [
        {
          "name": "RateLimitEntry",
          "fields": [
            {
              "name": "entry_id",
              "type": "uuid",
              "constraints": "primary_key"
            },
            {
              "name": "ip_address",
              "type": "string",
              "constraints": "inet"
            },
            {
              "name": "request_count",
              "type": "integer",
              "constraints": "max 1000 per window per SR-014"
            },
            {
              "name": "window_start",
              "type": "timestamp",
              "constraints": "rolling 60 seconds"
            },
            {
              "name": "is_rejected",
              "type": "boolean",
              "constraints": "true if > 1000"
            }
          ],
          "relationships": [
            {
              "to": null,
              "type": "one_to_one"
            }
          ]
        },
        {
          "name": "MaliciousRequest",
          "fields": [
            {
              "name": "request_id",
              "type": "uuid",
              "constraints": "primary_key"
            },
            {
              "name": "payload",
              "type": "string",
              "constraints": "sanitized"
            },
            {
              "name": "detection_time",
              "type": "timestamp",
              "constraints": "not_null"
            },
            {
              "name": "threat_indicator_id",
              "type": "uuid",
              "constraints": "references ThreatIndicator"
            },
            {
              "name": "source_ip",
              "type": "string",
              "constraints": "inet"
            }
          ],
          "relationships": [
            {
              "to": "ThreatIndicator",
              "type": "many_to_one",
              "foreign_key": "threat_indicator_id",
              "direction": "child references parent"
            }
          ]
        },
        {
          "name": "ThreatIndicator",
          "fields": [
            {
              "name": "indicator_id",
              "type": "uuid",
              "constraints": "primary_key"
            },
            {
              "name": "indicator_type",
              "type": "string",
              "constraints": "url_hash, slug, ip"
            },
            {
              "name": "source_feed",
              "type": "string",
              "constraints": "integrated_feed_name"
            },
            {
              "name": "active",
              "type": "boolean",
              "constraints": "true if current"
            },
            {
              "name": "updated_at",
              "type": "timestamp",
              "constraints": "update <= 15 min per SR-013"
            }
          ],
          "relationships": [
            {
              "to": null,
              "type": "one_to_one"
            }
          ]
        }
      ]
    },
    {
      "component_id": "comp-sec-transport-enforcer",
      "entities": [
        {
          "name": "SecureChannelConfig",
          "fields": [
            {
              "name": "config_id",
              "type": "uuid",
              "constraints": "primary_key"
            },
            {
              "name": "protocol",
              "type": "string",
              "constraints": "enum: https, http"
            },
            {
              "name": "hsts_enabled",
              "type": "boolean",
              "constraints": "true"
            },
            {
              "name": "redirect_status_code",
              "type": "integer",
              "constraints": "301 or 302"
            }
          ],
          "relationships": [
            {
              "to": null,
              "type": "one_to_one"
            }
          ]
        }
      ]
    },
    {
      "component_id": "graceful-shutdown-coordinator",
      "entities": [
        {
          "name": "ShutdownSignal",
          "fields": [
            {
              "name": "signal_id",
              "type": "uuid",
              "constraints": "primary_key"
            },
            {
              "name": "signal_type",
              "type": "string",
              "constraints": "SIGTERM, SIGINT"
            },
            {
              "name": "process_id",
              "type": "integer",
              "constraints": "os_pid"
            },
            {
              "name": "drain_window_ms",
              "type": "integer",
              "constraints": "configured_timeout"
            },
            {
              "name": "received_at",
              "type": "timestamp",
              "constraints": "not_null"
            }
          ],
          "relationships": [
            {
              "to": null,
              "type": "one_to_one"
            }
          ]
        }
      ]
    }
  ]
}
